from django.db import migrations

# Batch 2 of the catalog parameter-standard sweep: files_search / media_voice /
# desktop_ui / firmware_iot. User values live in [[ ]] at the top, runtime values
# use {{ }}, angle brackets < > stay report-slots-only, and every C:/Temp scaffold
# is moved to {{TEMPLATES}} / {{TEMP}} (the app dirs, per the Temp/Templates policy).
# Only promptContent is rewritten; idPrompt / promptName / category / sort_rank /
# hidden are untouched, so catalog ordering and contiguity hold. (Batch 1 =
# migration 0183, security_recon.) Payload is base64 because the firmware demo
# prompts contain literal triple quotes (content=\'\'\'<CODE>\'\'\').

_NEW_B64 = ""


def _apply(apps, schema_editor):
    import json
    import base64
    Prompt = apps.get_model("agent", "Prompt")
    data = json.loads(base64.b64decode(_NEW_B64).decode("utf-8"))
    for pid, content in data.items():
        Prompt.objects.filter(idPrompt=int(pid)).update(promptContent=content)


def _noop(apps, schema_editor):
    pass


class Migration(migrations.Migration):
    dependencies = [("agent", "0183_standardize_security_recon_prompts")]
    operations = [migrations.RunPython(_apply, _noop)]
